#\n#!/usr/bin/env python3\nimport numpy as np\nimport pandas as pd\nfrom mtf_data import get_htf_data, align_htf_to_ltf\n\n# Hypothesis: 6h Donchian(20) breakout with 1d trend filter (EMA200) and volume confirmation.\n# Donchian breakouts capture momentum in trending markets. 1d EMA200 filter ensures we trade\n# only in the direction of the higher timeframe trend, reducing false breakouts.\n# Volume confirmation ensures institutional participation. Works in bull markets (breakouts up)\n# and bear markets (breakouts down). Target: 15-35 trades/year by requiring 20-period high/low\n# breakout, EMA200 filter, and volume > 1.5x average.\n\nname = \"exp_13647_6h_donchian20_1d_ema200_vol_v1\"\ntimeframe = \"6h\"\nleverage = 1.0\n\n# Parameters\nDONCHIAN_PERIOD = 20\nEMA_TREND_PERIOD = 200\nVOLUME_MA_PERIOD = 20\nVOLUME_THRESHOLD = 1.5\nSIGNAL_SIZE = 0.25\nATR_PERIOD = 14\nATR_STOP_MULTIPLIER = 2.0\n\ndef calculate_donchian(high, low, period):\n    \"\"\"Calculate Donchian upper and lower bands\"\"\"\n    upper = pd.Series(high).rolling(window=period, min_periods=period).max().values\n    lower = pd.Series(low).rolling(window=period, min_periods=period).min().values\n    return upper, lower\n\ndef calculate_ema(close, period):\n    \"\"\"Calculate EMA\"\"\"\n    return pd.Series(close).ewm(span=period, adjust=False, min_periods=period).mean().values\n\ndef calculate_atr(high, low, close, period):\n    \"\"\"Calculate ATR using Wilder's smoothing\"\"\"\n    tr1 = high - low\n    tr2 = np.abs(high - np.roll(close, 1))\n    tr3 = np.abs(low - np.roll(close, 1))\n    tr = np.maximum(np.maximum(tr1, tr2), tr3)\n    tr[0] = tr1[0]\n    atr = pd.Series(tr).ewm(alpha=1/period, adjust=False, min_periods=period).mean().values\n    return atr\n\ndef generate_signals(prices):\n    n = len(prices)\n    if n < 200:\n        return np.zeros(n)\n    \n    # Load 1d data for trend filter ONCE before loop\n    df_1d = get_htf_data(prices, '1d')\n    \n    # Calculate 1d EMA200 for trend filter\n    close_1d = df_1d['close'].values\n    ema_1d = calculate_ema(close_1d, EMA_TREND_PERIOD)\n    ema_1d_aligned = align_htf_to_ltf(prices, df_1d, ema_1d)\n    \n    # Calculate 6h indicators\n    high = prices['high'].values\n    low = prices['low'].values\n    close = prices['close'].values\n    volume = prices['volume'].values\n    \n    # Donchian bands\n    upper, lower = calculate_donchian(high, low, DONCHIAN_PERIOD)\n    \n    # ATR for stop loss\n    atr = calculate_atr(high, low, close, ATR_PERIOD)\n    \n    # Volume MA\n    volume_ma = pd.Series(volume).rolling(window=VOLUME_MA_PERIOD, min_periods=VOLUME_MA_PERIOD).mean().values\n    \n    signals = np.zeros(n)\n    position = 0  # 0: flat, 1: long, -1: short\n    entry_price = 0.0\n    stop_price = 0.0\n    \n    # Start from warmup period\n    start = max(DONCHIAN_PERIOD, EMA_TREND_PERIOD, VOLUME_MA_PERIOD, ATR_PERIOD) + 1\n    \n    for i in range(start, n):\n        # Skip if required data not available\n        if np.isnan(ema_1d_aligned[i]) or np.isnan(upper[i]) or np.isnan(lower[i]) or np.isnan(volume_ma[i]):\n            if position != 0:\n                signals[i] = position * SIGNAL_SIZE\n            else:\n                signals[i] = 0.0\n            continue\n        \n        # Check stoploss\n        if position == 1:  # long position\n            if close[i] <= stop_price:\n                signals[i] = 0.0\n                position = 0\n                continue\n        elif position == -1:  # short position\n            if close[i] >= stop_price:\n                signals[i] = 0.0\n                position = 0\n                continue\n        \n        # Volume confirmation\n        volume_ok = volume[i] > (volume_ma[i] * VOLUME_THRESHOLD)\n        \n        # Trend direction from 1d EMA200\n        uptrend = close[i] > ema_1d_aligned[i]\n        downtrend = close[i] < ema_1d_aligned[i]\n        \n        # Donchian breakout signals\n        breakout_up = close[i] > upper[i-1]  # break above previous upper band\n        breakout_down = close[i] < lower[i-1]  # break below previous lower band\n        \n        # Generate signals\n        if position == 0:\n            if breakout_up and volume_ok and uptrend:\n                signals[i] = SIGNAL_SIZE\n                position = 1\n                entry_price = close[i]\n                stop_price = entry_price - (ATR_STOP_MULTIPLIER * atr[i])\n            elif breakout_down and volume_ok and downtrend:\n                signals[i] = -SIGNAL_SIZE\n                position = -1\n                entry_price = close[i]\n                stop_price = entry_price + (ATR_STOP_MULTIPLIER * atr[i])\n            else:\n                signals[i] = 0.0\n        elif position == 1:\n            # Exit long on Donchian breakdown or stop loss\n            if close[i] < lower[i-1]:\n                signals[i] = 0.0\n                position = 0\n            else:\n                signals[i] = SIGNAL_SIZE\n        elif position == -1:\n            # Exit short on Donchian breakout or stop loss\n            if close[i] > upper[i-1]:\n                signals[i] = 0.0\n                position = 0\n            else:\n                signals[i] = -SIGNAL_SIZE\n    \n    return signals\n